-- Esquema de base de datos para BioPractor.
-- Ejecuta este archivo completo en el SQL Editor de tu proyecto de Supabase
-- (https://supabase.com/dashboard/project/_/sql/new).

create extension if not exists "pgcrypto";

create table if not exists products (
  id uuid primary key default gen_random_uuid(),
  slug text unique not null,
  name text not null,
  reference text not null default '',
  category_slugs text[] not null default '{}',
  price integer not null default 0,
  short_description text not null default '',
  description text not null default '',
  images text[] not null default '{}',
  featured boolean not null default false,
  archived boolean not null default false,
  views integer not null default 0,
  whatsapp_clicks integer not null default 0,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);

create index if not exists products_archived_idx on products (archived);
create index if not exists products_category_slugs_idx on products using gin (category_slugs);

-- Incrementos atómicos (evitan condiciones de carrera con muchas visitas a la vez).
create or replace function increment_product_view(p_slug text)
returns void as $$
  update products set views = views + 1
  where slug = p_slug and archived = false;
$$ language sql;

create or replace function increment_whatsapp_click(p_slug text)
returns void as $$
  update products set whatsapp_clicks = whatsapp_clicks + 1
  where slug = p_slug and archived = false;
$$ language sql;

-- Catalogo real de BioPractor (153 productos), generado a partir de:
--   - "Listado productos 2026 (3).xlsx" (precios actualizados por referencia)
--   - "Catalogo AlmaVida actualizado (1).pdf" (nombres, descripciones y fotos)
-- Las fotos viven en public/products/<slug>.webp dentro del proyecto Next.js.
on conflict (slug) do nothing;
